#include <string>
#include <string_view>

// The hierarchy below is intentionally NON-virtual: speak() is an ordinary
// member function. That is the whole point of this lesson -- you will observe
// that a call through a base handle binds at COMPILE TIME to Animal::speak,
// even when the real object is a Cat or Dog.
class Animal
{
    std::string m_name;

public:
    Animal(const std::string& name)
        : m_name{ name }
    {
    }

    const std::string& getName() const { return m_name; }
    std::string_view speak() const { return "..."; }
};

class Cat : public Animal
{
public:
    Cat(const std::string& name)
        : Animal{ name }
    {
    }

    std::string_view speak() const { return "Meow"; }
};

class Dog : public Animal
{
public:
    Dog(const std::string& name)
        : Animal{ name }
    {
    }

    std::string_view speak() const { return "Woof"; }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::string name{};
        std::cin >> type >> name;

        // Construct the matching derived object (Cat or Dog) for this line, then
        // call speak() TWO ways on that SAME object:
        //   (a) directly on the derived object -> gives the derived sound.
        //   (b) through a base handle bound to it. Bind a const Animal& to the
        //       object: what static type does that handle have, and which
        //       speak() does a non-virtual call therefore select?
        // TODO: produce the (a) and (b) results and print:
