#include <iostream>
#include <string>

// The hierarchy below is intentionally NON-virtual. describe() is an ordinary
// member function, so a call through a Shape& binds to Shape::describe at
// COMPILE TIME -- the derived override is invisible through the reference.
class Shape
{
    std::string m_name;

public:
    Shape(const std::string& name)
        : m_name{ name }
    {
    }

    const std::string& getName() const { return m_name; }
    std::string describe() const { return m_name + ": generic"; }
};

class Circle : public Shape
{
    int m_radius{};

public:
    Circle(const std::string& name, int radius)
        : Shape{ name }
        , m_radius{ radius }
    {
    }

    std::string describe() const
    {
        return getName() + ": circle r=" + std::to_string(m_radius);
    }
};

class Square : public Shape
{
    int m_side{};

public:
    Square(const std::string& name, int side)
        : Shape{ name }
        , m_side{ side }
    {
    }

    std::string describe() const
    {
        return getName() + ": square s=" + std::to_string(m_side);
    }
};

// This free function only ever sees a Shape&. Because describe() is non-virtual,
// the call below always prints the generic Shape form, regardless of the real
// object type passed in.
void report(const Shape& s)
{
    std::cout << s.describe() << '\n';
}

